import{_ as t,a as e,b as o,c as r,d as l}from"./chunks/编辑配置.T0puvWjh.js";import{_ as d,o as i,c as s,a2 as n}from"./chunks/framework.DnrXFDHb.js";const B=JSON.parse('{"title":"Telegram チャンネルの追加","description":"","frontmatter":{},"headers":[],"relativePath":"ja-JP/upload/telegram.md","filePath":"ja-JP/upload/telegram.md","lastUpdated":1781962217000}'),h={name:"ja-JP/upload/telegram.md"};function c(p,a,m,g,b,u){return i(),s("div",null,[...a[0]||(a[0]=[n('<h1 id="telegram-チャンネルの追加" tabindex="-1">Telegram チャンネルの追加 <a class="header-anchor" href="#telegram-チャンネルの追加" aria-label="Permalink to &quot;Telegram チャンネルの追加&quot;">​</a></h1><p>Telegram チャンネルを保存先として使うには、Bot を作成し、その Bot を保存用チャンネルへ追加します。</p><h2 id="事前に用意するもの" tabindex="-1">事前に用意するもの <a class="header-anchor" href="#事前に用意するもの" aria-label="Permalink to &quot;事前に用意するもの&quot;">​</a></h2><table tabindex="0"><thead><tr><th>必要なもの</th><th>用途</th></tr></thead><tbody><tr><td>Telegram アカウント</td><td>Bot とチャンネルを作成します</td></tr><tr><td><code>@BotFather</code></td><td>Telegram Bot を作成します</td></tr><tr><td>Telegram チャンネル</td><td>ファイルの保存先</td></tr><tr><td><code>@userinfobot</code></td><td>チャンネルの Chat ID を確認します</td></tr></tbody></table><h2 id="bot-を作成する" tabindex="-1">Bot を作成する <a class="header-anchor" href="#bot-を作成する" aria-label="Permalink to &quot;Bot を作成する&quot;">​</a></h2><ol><li>Telegram で <code>@BotFather</code> を検索します。</li><li>チャットを開き、<code>/newbot</code> を送信します。</li><li>表示名と username を入力します。username は通常 <code>bot</code> で終わる必要があります。</li><li>作成後に返される Token をコピーします。</li></ol><p><img src="'+t+'" alt="Bot Token" loading="lazy"></p><h2 id="保存用チャンネルを作成する" tabindex="-1">保存用チャンネルを作成する <a class="header-anchor" href="#保存用チャンネルを作成する" aria-label="Permalink to &quot;保存用チャンネルを作成する&quot;">​</a></h2><p>Telegram で新しいチャンネルを作成します。公開チャンネルでも非公開チャンネルでも利用できます。</p><p><img src="'+e+'" alt="チャンネル作成" loading="lazy"></p><h2 id="bot-をチャンネルへ追加する" tabindex="-1">Bot をチャンネルへ追加する <a class="header-anchor" href="#bot-をチャンネルへ追加する" aria-label="Permalink to &quot;Bot をチャンネルへ追加する&quot;">​</a></h2><p>作成したチャンネルの設定から、先ほどの Bot をメンバーまたは管理者として追加します。</p><p><img src="'+o+'" alt="Bot 追加" loading="lazy"></p><p>安定してアップロードするため、Bot には管理者権限を付けるのがおすすめです。</p><h2 id="chat-id-を取得する" tabindex="-1">Chat ID を取得する <a class="header-anchor" href="#chat-id-を取得する" aria-label="Permalink to &quot;Chat ID を取得する&quot;">​</a></h2><ol><li>Telegram で <code>@userinfobot</code> を検索します。</li><li><code>Start</code> を押します。</li><li>Bot の選択肢から <code>Channel</code> を選びます。</li><li>対象チャンネルのメッセージを <code>@userinfobot</code> へ送ります。</li><li><code>Id: -100...</code> で始まる数字をコピーします。</li></ol><p><img src="'+r+'" alt="Chat ID" loading="lazy"></p><h2 id="imgbed-へ入力する" tabindex="-1">ImgBed へ入力する <a class="header-anchor" href="#imgbed-へ入力する" aria-label="Permalink to &quot;ImgBed へ入力する&quot;">​</a></h2><p>アップロード設定で <code>Telegram</code> を選びます。</p><table tabindex="0"><thead><tr><th>項目</th><th>入力内容</th></tr></thead><tbody><tr><td>チャンネル名</td><td>例：<code>Telegram Main</code></td></tr><tr><td>Bot Token</td><td><code>@BotFather</code> で取得した Token</td></tr><tr><td>Session ID / Chat ID</td><td><code>-100</code> で始まるチャンネル ID</td></tr><tr><td>Relay Proxy URL</td><td>任意。Telegram への接続が不安定な場合だけ入力</td></tr><tr><td>備考</td><td>任意</td></tr></tbody></table><p><img src="'+l+`" alt="Telegram 設定" loading="lazy"></p><h2 id="確認方法" tabindex="-1">確認方法 <a class="header-anchor" href="#確認方法" aria-label="Permalink to &quot;確認方法&quot;">​</a></h2><ol><li>保存後に Telegram チャンネルカードが表示される。</li><li>テスト画像をアップロードする。</li><li>対象 Telegram チャンネルにファイルが投稿される。</li><li>ImgBed のリンクが開ける。</li></ol><h2 id="クイック手順" tabindex="-1">クイック手順 <a class="header-anchor" href="#クイック手順" aria-label="Permalink to &quot;クイック手順&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@BotFather で Bot を作成</span></span>
<span class="line"><span>-&gt; Bot Token をコピー</span></span>
<span class="line"><span>-&gt; Telegram チャンネルを作成</span></span>
<span class="line"><span>-&gt; Bot をチャンネルに追加し管理者権限を付与</span></span>
<span class="line"><span>-&gt; @userinfobot で -100 から始まる Chat ID を取得</span></span>
<span class="line"><span>-&gt; ImgBed に Bot Token と Chat ID を入力</span></span>
<span class="line"><span>-&gt; 保存してテストアップロード</span></span></code></pre></div><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ol><li>Telegram Bot: <a href="https://core.telegram.org/bots" target="_blank" rel="noreferrer">https://core.telegram.org/bots</a></li><li>Telegram Bot API: <a href="https://core.telegram.org/bots/api" target="_blank" rel="noreferrer">https://core.telegram.org/bots/api</a></li></ol>`,27)])])}const f=d(h,[["render",c]]);export{B as __pageData,f as default};
